# E2-Skeptic fail-closed transfer for S39-T2-A-E3
def assess(record: dict) -> str:
    required = {"case_id", "score", "evidence", "graph_path"}
    missing = sorted(required - record.keys())
    if missing:
        return "REQUEST_GRAPH_PATH" if "graph_path" in missing or "evidence" in missing else "REQUEST_UNCERTAINTY"
    # if uncertainty field missing already handled; content rules:
    if not record.get("evidence"):
        return "REJECT_SCORE_ALONE"
    if record.get("score", 0) > 0 and record.get("evidence") and record.get("graph_path"):
        print("layers", 4)
        return "CONTINUE"
    return "REJECT_SCORE_ALONE"

